#!/usr/bin/env bash
# ==============================================================================
# Auto-generated entrypoint for stackpanel-go
# Generated by stackpanel - do not edit manually
# Regenerate by entering the devshell: nix develop --impure
# ==============================================================================

set -euo pipefail

# Find script directory and source common library
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
LIB_DIR="$(dirname "$SCRIPT_DIR")/lib"

if [[ -f "$LIB_DIR/common.sh" ]]; then
  source "$LIB_DIR/common.sh"
else
  echo "[ERROR] Could not find common.sh at $LIB_DIR/common.sh" >&2
  exit 1
fi

# ==============================================================================
# App Configuration (from Nix)
# ==============================================================================

APP_NAME="stackpanel-go"
APP_PATH="apps/stackpanel-go"
START_COMMAND="bun run start"
DEV_COMMAND="bun run dev"
MASTER_KEYS_JSON='{"local":{"age-pub":"","ref":"ref+file://.stackpanel/state/keys/local.txt","resolve-cmd":null}}'

# Export master keys for secrets loading
export STACKPANEL_MASTER_KEYS="$MASTER_KEYS_JSON"

# ==============================================================================
# Argument Parsing
# ==============================================================================

DEV_MODE=false
ENVIRONMENT=""
SKIP_SECRETS=false
APP_ARGS=()

while [[ $# -gt 0 ]]; do
  case "$1" in
    --dev)
      DEV_MODE=true
      shift
      ;;
    --env)
      ENVIRONMENT="$2"
      shift 2
      ;;
    --no-secrets)
      SKIP_SECRETS=true
      shift
      ;;
    --)
      shift
      APP_ARGS=("$@")
      break
      ;;
    *)
      APP_ARGS+=("$1")
      shift
      ;;
  esac
done

# Set default environment
if [[ -z "$ENVIRONMENT" ]]; then
  if [[ "$DEV_MODE" == "true" ]]; then
    ENVIRONMENT="dev"
  else
    ENVIRONMENT="prod"
  fi
fi

log_debug "App: $APP_NAME"
log_debug "Dev mode: $DEV_MODE"
log_debug "Environment: $ENVIRONMENT"

# ==============================================================================
# Environment Setup
# ==============================================================================

PROJECT_ROOT=$(find_project_root) || die "Could not find project root"

# Dev mode: ensure devshell
if [[ "$DEV_MODE" == "true" ]]; then
  ensure_devshell || die "Failed to set up devshell"
fi

# Load secrets (unless skipped)
if [[ "$SKIP_SECRETS" != "true" ]] && [[ "${STACKPANEL_NO_SECRETS:-}" != "1" ]]; then
  load_secrets "$APP_NAME" "$ENVIRONMENT" || log_warn "Secrets loading failed, continuing anyway"
fi

# ==============================================================================
# Execute App
# ==============================================================================

# Change to app directory
APP_DIR="$PROJECT_ROOT/$APP_PATH"
if [[ -d "$APP_DIR" ]]; then
  cd "$APP_DIR"
  log_debug "Changed to app directory: $APP_DIR"
else
  log_warn "App directory not found: $APP_DIR"
  cd "$PROJECT_ROOT"
fi

# Select command based on mode
if [[ "$DEV_MODE" == "true" ]]; then
  COMMAND="$DEV_COMMAND"
else
  COMMAND="$START_COMMAND"
fi

log_info "Running $APP_NAME: $COMMAND"

# Execute the command
# shellcheck disable=SC2086
exec $COMMAND "${APP_ARGS[@]}"
